import React, { useEffect, useState } from 'react';

export const Rasp = () => {
  const [scheduleData, setScheduleData] = useState([]);

  useEffect(() => {
    // API endpoint URL'i
    const apiUrl = 'http://localhost:5555/schedule';

    // Veriyi çekme işlemi
    fetch(apiUrl)
      .then(response => response.json())
      .then(data => {
        // JSON yanıtından "schedule" verisini al ve state'i güncelle
        setScheduleData(data.schedule);
      })
      .catch(error => console.error('Error:', error));
  }, []); // useEffect sadece bir kere çağrılsın diye boş dependency array kullandık

  return (
    <div className="bg-white px-4 pt-3 pb-4 rounded-sm border border-gray-200 flex-1">
      <strong className="text-gray-700 font-medium">Расписания</strong>
      <div className="border-x border-gray-200 rounded-sm mt-3">
        <table className="w-full text-gray-700">
          <thead>
            <tr>
              <th>Время</th>
              <th>День</th>
              <th>Предмет</th>
              <th>Группа</th>
              <th>Преподаватель</th>
              <th>Курс</th>
              <th>Кабинет</th>
            </tr>
          </thead>
          <tbody>
            {scheduleData.map(item => (
              <tr key={item._id}>
                <td>{item.time.time}</td>
                <td>{item.day.day}</td>
                <td>{item.predmet.predmet}</td>
                <td>{item.group.group_number}</td>
                <td>{item.teacher.teacher}</td>
                <td>{item.group.kurs}</td>
                <td>{item.room}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default Rasp;
